import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

const LABELS = {
  '1': { text: 'ьзДэЦЙьдС', color: '#4caf50' },
  '0': { text: 'ыкиьзСьЩДыгМ', color: '#f44336' },
};

const TAG_COLORS = ['#1976d2', '#ff9800', '#8e24aa']; // ьзАьЧн, ьЧ░ыа╣ыМА, ьЛдыае

const REGION_COLORS = {
  'ьДЬьЪ╕': '#1976d2', 'ъ▓╜ъ╕░': '#388e3c', 'ьЭ╕ь▓Ь': '#0288d1', 'ы╢АьВ░': '#ff7043', 'ыМАъ╡м': '#8d6e63', 'ъ╕░эГА': '#607d8b'
};
const AGE_COLORS = {
  '10ыМА': '#ffd600', '20ыМА': '#ffb300', '30ыМА': '#ff7043', '40ыМА': '#8e24aa', '50ыМА ьЭ┤ьГБ': '#455a64', 'ьЮРьЬа': '#90caf9'
};
const SKILL_COLORS = {
  'ь┤Иы│┤': '#81c784', 'ьдСъ╕Й': '#1976d2', 'ъ│аьИШ': '#d32f2f', 'ьЮРьЬа': '#bdbdbd'
};

function getMemberTagColor(memberCount) {
  if (memberCount >= 8) return '#4caf50'; // ь┤ИыбЭ
  if (memberCount >= 5) return '#ff9800'; // ьг╝эЩй
  return '#f44336'; // ы╣иъ░Х
}

function getTagColor(tag, idx) {
  if (idx === 0) return REGION_COLORS[tag] || '#607d8b';
  if (idx === 1) return AGE_COLORS[tag] || '#607d8b';
  if (idx === 2) return SKILL_COLORS[tag] || '#607d8b';
  return '#607d8b';
}

function PostsList() {
  const [posts, setPosts] = useState([]);
  const [showRecruiting, setShowRecruiting] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    fetch(`/api/posts${showRecruiting ? '?recruiting=true' : ''}`)
      .then(res => res.json())
      .then(data => setPosts(data.posts || []));
  }, [showRecruiting]);

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #43a047 80%, #fff 100%)',
      paddingTop: 60,
      paddingBottom: 60,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
    }}>
      <div style={{ maxWidth: 900, width: '100%', margin: '0 auto', marginTop: 32 }}>
        <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: 18 }}>
          <label style={{ color: '#fff', fontWeight: 600, fontSize: 15, background: 'rgba(0,0,0,0.08)', borderRadius: 8, padding: '4px 12px' }}>
            <input type="checkbox" checked={showRecruiting} onChange={e => setShowRecruiting(e.target.checked)} style={{ marginRight: 6 }} />
            ьзДэЦЙьдСызМ эСЬьЛЬ
          </label>
        </div>
        <div style={{
          display: 'flex',
          alignItems: 'center',
          background: 'rgba(255,255,255,0.85)',
          borderRadius: 14,
          boxShadow: '0 1px 4px #b0c4de',
          marginBottom: 18,
          padding: '12px 24px',
          fontWeight: 700,
          fontSize: 16,
          color: '#388e3c',
          gap: 18,
        }}>
          <span style={{ minWidth: 70, textAlign: 'center' }}>ьГБэГЬ</span>
          <span style={{ minWidth: 90, textAlign: 'center' }}>ыкиьзСьЭ╕ьЫР</span>
          <span style={{ flex: 3 }}>ьаЬыкй</span>
          <span style={{ flex: 1 }}>ьЮСьД▒ьЮР</span>
          <span style={{ flex: 1 }}>ьЮСьД▒ьЭ╝</span>
          <span style={{ flex: 0.7, textAlign: 'right' }}>ьб░эЪМьИШ</span>
        </div>
        {posts.map(post => {
          const memberTagColor = getMemberTagColor(post.member_count);
          const tags = [post.region, post.age_group, post.skill_level].filter(Boolean);
          return (
            <div
              key={post.id}
              onClick={() => navigate(`/posts/${post.id}`)}
              style={{
                display: 'flex',
                alignItems: 'center',
                background: '#fff',
                borderRadius: 16,
                boxShadow: '0 2px 8px #b0c4de',
                marginBottom: 18,
                padding: '18px 24px',
                cursor: 'pointer',
                transition: 'transform 0.1s',
                borderLeft: `10px solid ${LABELS[String(post.is_recruiting)]?.color}`,
                gap: 18,
              }}
            >
              <div style={{ display: 'flex', alignItems: 'center', minWidth: 0, gap: 8, flex: 3 }}>
                <span style={{
                  display: 'inline-block',
                  minWidth: 70,
                  textAlign: 'center',
                  padding: '4px 0',
                  borderRadius: 12,
                  background: LABELS[String(post.is_recruiting)]?.color,
                  color: '#fff',
                  fontWeight: 700,
                  fontSize: 15,
                  marginRight: 6,
                  flexShrink: 0,
                }}>{LABELS[String(post.is_recruiting)]?.text}</span>
                <span style={{
                  display: 'inline-block',
                  minWidth: 70,
                  textAlign: 'center',
                  padding: '4px 0',
                  borderRadius: 12,
                  background: memberTagColor,
                  color: '#fff',
                  fontWeight: 700,
                  fontSize: 15,
                  marginRight: 10,
                  flexShrink: 0,
                }}>{post.member_count}ыкЕ</span>
                <span style={{
                  fontWeight: 700,
                  fontSize: 18,
                  color: '#222',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap',
                  minWidth: 0,
                  maxWidth: 220,
                  display: 'inline-block',
                  verticalAlign: 'middle',
                }}>{post.title}</span>
                {tags.length > 0 && (
                  <span style={{ display: 'inline-flex', gap: 4, marginLeft: 10, flexShrink: 0, verticalAlign: 'middle' }}>
                    {tags.map((tag, i) => (
                      <span key={i} style={{
                        display: 'inline-block',
                        background: getTagColor(tag, i),
                        color: '#fff',
                        borderRadius: 8,
                        padding: '2px 10px',
                        fontSize: 14,
                        fontWeight: 600,
                        marginLeft: 0,
                        whiteSpace: 'nowrap',
                        verticalAlign: 'middle',
                      }}>{tag}</span>
                    ))}
                  </span>
                )}
              </div>
              <span style={{ flex: 1, color: '#388e3c', fontWeight: 600, fontSize: 15 }}>{post.author}</span>
              <span style={{ flex: 1, color: '#888', fontSize: 14 }}>{new Date(post.created_at).toLocaleDateString()}</span>
              <span style={{ flex: 0.7, color: '#607d8b', fontWeight: 700, fontSize: 15, textAlign: 'right' }}>{post.views}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

export default PostsList;
